def is_valid_date(date_str):
    parts = date_str.split('/')
    if len(parts) != 3:
        return False
    try:
        month, day, year = int(parts[0]), int(parts[1]), int(parts[2])
    except ValueError:
        return False
    if year < 1 or month < 1 or month > 12 or day < 1:
        return False
    days_in_month = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    if month == 2 and (year % 4 == 0 and (year % 100 != 0 or year % 400 == 0)):
        days_in_month[2] = 29
    return day <= days_in_month[month]

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_valid_christmas(self):
        self.assertTrue(is_valid_date("12/25/2023"))

    def test_leap_year_feb29(self):
        self.assertTrue(is_valid_date("02/29/2024"))

    def test_non_leap_year_feb29(self):
        self.assertFalse(is_valid_date("02/29/2023"))

    def test_hidden_invalid_month_13(self):
        self.assertFalse(is_valid_date("13/01/2020"))

    def test_hidden_april_31(self):
        self.assertFalse(is_valid_date("04/31/2020"))

    def test_hidden_century_leap_year_2000(self):
        self.assertTrue(is_valid_date("02/29/2000"))

    def test_hidden_century_non_leap_1900(self):
        self.assertFalse(is_valid_date("02/29/1900"))

    def test_hidden_month_zero(self):
        self.assertFalse(is_valid_date("00/15/2020"))

    def test_hidden_day_zero(self):
        self.assertFalse(is_valid_date("06/00/2020"))

    def test_hidden_bad_format_no_slashes(self):
        self.assertFalse(is_valid_date("abc"))

    def test_hidden_non_numeric_parts(self):
        self.assertFalse(is_valid_date("ab/cd/efgh"))

    def test_hidden_last_day_of_year(self):
        self.assertTrue(is_valid_date("12/31/2023"))

    def test_hidden_min_valid_date(self):
        self.assertTrue(is_valid_date("01/01/0001"))

if __name__ == '__main__':
    unittest.main()
